"""Baked reference data — embeddings and class mapping encoded in Python.
Avoids using weight file slots for reference data."""

import numpy as np
import json
import base64

_EMB_SHAPE = (357, 1408)
_EMB_DTYPE = np.float16

_EMB_B64 = """"""

_MAPPING_B64 = """"""


def load_reference_embeddings() -> np.ndarray:
    raw = base64.b64decode(_EMB_B64)
    return np.frombuffer(raw, dtype=_EMB_DTYPE).reshape(_EMB_SHAPE).copy()


def load_class_mapping() -> dict[int, int]:
    raw = base64.b64decode(_MAPPING_B64)
    mapping = json.loads(raw.decode())
    return {int(k): int(v) for k, v in mapping.items()}
